import{_ as t,o as s,c as a,ae as n}from"./chunks/framework.BIONGpTb.js";const p=JSON.parse('{"title":"Security and safety","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security.md","filePath":"concepts/security.md"}'),r={name:"concepts/security.md"};function o(i,e,d,l,c,h){return s(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="security-and-safety" tabindex="-1">Security and safety <a class="header-anchor" href="#security-and-safety" aria-label="Permalink to &quot;Security and safety&quot;">​</a></h1><p>Eclipse Docks runs entirely in the browser. <strong>There is no separate “extension process”</strong> comparable to a browser extension’s isolated world or an OS-level sandbox. Understanding that model helps you ship apps that match your threat model.</p><p><strong>This model is already familiar from desktop IDEs:</strong> Eclipse RCP and similar hosts run plugins in the <strong>same process</strong> as the shell—OSGi gives modular boundaries and class loaders, not a hard security sandbox. Teams choose what to install and trust their update sites; the platform stays integrated and lean. <strong>A browser deployment adds typical web concerns</strong> (origins, HTTPS, untrusted links, rich embedded content), so you still want explicit trust in extensions and catalogs, hardened hosting, and the usual browser hygiene—not because in-process extensions are novel, but because the surrounding threat model differs from a locked-down desktop install.</p><h2 id="extension-trust-model" tabindex="-1">Extension trust model <a class="header-anchor" href="#extension-trust-model" aria-label="Permalink to &quot;Extension trust model&quot;">​</a></h2><p><strong>Extensions execute in the same JavaScript realm as your app</strong> — same origin, same DOM, same <code>window</code>, and access to the same core services (workspace, settings, commands, network APIs the browser allows).</p><ul><li>Extensions are <strong>not</strong> moved into dedicated web workers or iframes for isolation. Workers exist for specific features (for example language runtimes or heavy compute), but <strong>extension registration and UI run on the main thread</strong> with full integration into the host. That keeps the platform <strong>lightweight</strong> and avoids duplicating large APIs across process boundaries.</li><li><strong>App authors must trust every extension</strong> they ship: packages listed in <code>AppDefinition.extensions</code>, modules loaded via extension URLs, and anything surfaced through marketplace catalogs you configure.</li><li>Treat third-party extension URLs and catalog hosts like <strong>application dependencies</strong>: prefer pinned versions, first-party or audited sources, and HTTPS. A hostile or compromised extension has the same capabilities as first-party code in your bundle.</li></ul><h2 id="workspace-and-user-generated-content" tabindex="-1">Workspace and user-generated content <a class="header-anchor" href="#workspace-and-user-generated-content" aria-label="Permalink to &quot;Workspace and user-generated content&quot;">​</a></h2><p>The workspace can contain arbitrary files (documents, notebooks, markdown). Some views render rich content (for example markdown as HTML). <strong>Untrusted workspace content should be handled with the same care as in any rich web app</strong> — be cautious when opening workspaces from unknown sources, and prefer extensions or configurations that sanitize or restrict rendering where your use case requires it.</p><h2 id="settings-credentials-and-storage" tabindex="-1">Settings, credentials, and storage <a class="header-anchor" href="#settings-credentials-and-storage" aria-label="Permalink to &quot;Settings, credentials, and storage&quot;">​</a></h2><p>Settings and workspace metadata typically live in <strong>browser storage</strong> (for example IndexedDB). Anything in that storage is readable by code running on your origin — including extensions. <strong>Do not assume secrets are hidden from extensions</strong>; use short-lived tokens, backend-held secrets, or the platform’s auth patterns appropriate to your deployment.</p><h2 id="optional-features-that-widen-the-surface" tabindex="-1">Optional features that widen the surface <a class="header-anchor" href="#optional-features-that-widen-the-surface" aria-label="Permalink to &quot;Optional features that widen the surface&quot;">​</a></h2><p>Some extensions integrate with external services or browser capabilities that deserve an explicit review for your product:</p><ul><li><strong>External extension registration</strong> — Loading an extension module from a URL runs that code with host privileges. Restrict who can trigger this in your deployment if needed.</li><li><strong>Marketplace / catalog URLs</strong> — Catalogs list extensions users can install; trust the catalog host and transport (HTTPS).</li><li><strong>WebMCP and similar bridges</strong> — Features that expose commands or tools to external agents increase the blast radius if an agent is misused. Enable only when it matches your safety requirements.</li></ul><h2 id="deployment-hygiene" tabindex="-1">Deployment hygiene <a class="header-anchor" href="#deployment-hygiene" aria-label="Permalink to &quot;Deployment hygiene&quot;">​</a></h2><ul><li>Serve your app over <strong>HTTPS</strong> in production.</li><li>Keep dependencies and extensions <strong>updated</strong>; supply-chain hygiene applies to npm packages and to any URL-loaded modules alike.</li><li>If you embed Docks in a larger product, align <strong>Content-Security-Policy</strong> and related headers with your security team’s baseline (the framework does not replace CSP).</li></ul><p>For architecture context, see <a href="/docs/concepts/architecture.html">Architecture</a> and <a href="/docs/concepts/extensions.html">Extensions</a>.</p>',16)])])}const g=t(r,[["render",o]]);export{p as __pageData,g as default};
